Cte.Query:

					SELECT {{
								-Fields 
									-Dimension: Users 
										-Table: UsersCte
									-Dimension: UsersPointOfSale 
										-Table: UsersPointOfSaleCte
									-Dimension: PointsOfSale 
										-Table: PointsOfSaleCte
									-Dimension: Products 
										-Table: ProductsCte
									-Dimension:
										-Name:Calendar 
										-Table:CalendarCte 
										-WithPrimaryKey
									-WithComma
                    		}}
                    		SalesAnalysis.SalesQuantity, SalesAnalysis.SalesAmountTaxesIncluded, SalesAnalysis.SalesAmountTaxesExcluded,
                    		SalesAnalysis.Refund, Accumulated.Transactions
                    	FROM Fact.SalesAnalysis
                    	{{
                    		-InnerJoin 
                    			-Dimension: UsersPointOfSale 
	                    			-IfRequest: Users
	                    			-IfRequest: PointsOfSale 
	                    			-Table: UsersPointOfSaleCte 
                    			-Table: SalesAnalysis 
                    			-On: UserPointOfSaleId-UserPointOfSaleId
                    	}}
                    	{{
                    		-InnerJoin 
                    			-Dimension: Users 
                    				-Table: UsersCte
								-Table: UsersPointOfSaleCte
								-On:UserId-UserId
                    	}}
                    	{{
                    		-InnerJoin 
                    			-Dimension: PointsOfSale 
                    				-Table:PointsOfSaleCte
								-Table:UsersPointOfSaleCte
								-On:PointOfSaleId-PointOfSaleId
                    	}}
                    	{{
                    		-InnerJoin 
                    			-Dimension: Products 
                    				-Table: ProductsCte
								-Table: SalesAnalysis
								-On: ProductId-ProductId
                    	}}
                    	{{
                    		-InnerJoin 
                    			-Dimension: Calendar 
                    				-Required
                    				-Table: CalendarCte
								-Table:SalesAnalysis
								-On:Date-Date
                    	}}

Then.Query:
OUTER APPLY (SELECT COUNT(DISTINCT SalesAnalysisAccumulated.Ticket) AS Transactions FROM Fact.SalesAnalysis AS SalesAnalysisAccumulated {{ -InnerJoin -Dimension: UsersPointOfSale -IfRequest: Users -IfRequest: PointsOfSale -Table: UsersPointOfSaleCte -Alias: UsersPointOfSaleAccumulatedCte -Table: SalesAnalysisAccumulated -On: UserPointOfSaleId-UserPointOfSaleId }} {{ -InnerJoin -Dimension: Users -Table: UsersCte -Alias: UsersAccumulatedCte -Table: UsersPointOfSaleAccumulatedCte -On: UserId-UserId }} {{ -InnerJoin -Dimension: PointsOfSale -Table: PointsOfSaleCte -Alias: PointsOfSaleAccumulatedCte -Table: UsersPointOfSaleAccumulatedCte -On: PointOfSaleId-PointOfSaleId }} {{ -InnerJoin -Dimension: Products -Table: ProductsCte -Alias: ProductsAccumulatedCte -Table: SalesAnalysisAccumulated -On: ProductId-ProductId }}
{{ -Where -Equal -Dimension: UsersPointOfSale -Table: UsersPointOfSaleCte -Table: UsersPointOfSaleAccumulatedCte -Template IsNull(Dimension.Field, '') = IsNull(Table.Field, '') -Equal -Dimension:Users -Table:UsersCte -Table:UsersAccumulatedCte -Template IsNull(Dimension.Field, '') = IsNull(Table.Field, '') -Equal -Dimension:PointsOfSale Table:PointsOfSaleCte -Table:PointsOfSaleAccumulatedCte -Template IsNull(Dimension.Field, '') = IsNull(Table.Field, '') -Equal -Dimension:Products -Table:ProductsCte -Table:ProductsAccumulatedCte -Template IsNull(Dimension.Field, '') = IsNull(Table.Field, '') -Additional SalesAnalysisAccumulated.Date BETWEEN @StartDate AND SalesAnalysis.Date AND SalesAnalysisAccumulated.Refund = 0 }}
-- Esto también hay que convertirlo WHERE IsNull(PointsOfSaleCte.[PointOfSale], '') = IsNull(PointsOfSaleAccumulatedCte.[PointOfSale], '') AND IsNull(PointsOfSaleCte.[ErpCode], '') = IsNull(PointsOfSaleAccumulatedCte.[ErpCode], '') AND IsNull(PointsOfSaleCte.[PointOfSaleImageUrl], '') = IsNull(PointsOfSaleAccumulatedCte.[PointOfSaleImageUrl], '')
AND SalesAnalysisAccumulated.Date BETWEEN @StartDate AND SalesAnalysis.Date AND SalesAnalysisAccumulated.Refund = 0
) AS Accumulated

Cte.Query:

					SELECT {{
								-Fields 
									-Dimension: Users
									-Dimension: UsersPointOfSale
									-Dimension: PointsOfSale
									-Dimension: Products
									-Dimension: Calendar 
										-WithPrimaryKey
									-WithComma
							}}
						    SUM(SalesQuantity) AS Sales, 
						    SUM(SalesAmountTaxesIncluded) AS SalesTaxesIncluded,
						    SUM(SalesAmountTaxesExcluded) AS SalesTaxesExcluded,
						    SUM(CASE WHEN Refund = 0 THEN SalesQuantity ELSE 0 END) AS SalesQuantityNoRefund, 
						    SUM(CASE WHEN Refund = 0 THEN SalesAmountTaxesIncluded ELSE 0 END) AS SalesAmountTaxesIncludedNoRefund,
						    COUNT(DISTINCT CASE WHEN Refund = 0 
					                                THEN Ticket 
					                                ELSE NULL 
					                        END) AS Transactions,
							 MAX(Transactions) AS TransactionsStartToDate
						FROM ({{
									-Subquery: SalesAnalysis 
							  }}
				              {{
				              		-Subquery: TransactionAccumulated 
				              }}
							) AS SalesAnalysisWithTransactions
	                    {{
							-GroupBy 
								-Dimension:Users
								-Dimension:UsersPointOfSale
								-Dimension:PointsOfSale
								-Dimension:Products
								-Dimension:Calendar 
									-WithPrimaryKey
                    	}}

Then.Cte:

		                    SELECT {{
										-Fields 
											-Dimension:Users 
												-Table:UsersCte
											-Dimension:UsersPointOfSale 
												-Table:UsersPointOfSaleCte
											-Dimension:PointsOfSale 
												-Table:PointsOfSaleCte
											-Dimension:Calendar 
												-Table:CalendarCte 
												-WithPrimaryKey
											-WithComma
                    				}}
				                    SUM(VendorAnalysis.SalesTarget) AS SalesTarget, 
				                    SUM(VendorAnalysis.AssignedHours) AS AssignedHours
			                    FROM Fact.VendorAnalysis
			                    {{
			                    	-InnerJoin 
			                    		-Dimension:UsersPointOfSale
			                    			-IfRequest: Users
			                    			-IfRequest: PointsOfSale
			                    			-Table:UsersPointOfSaleCte
			                    		-Table:VendorAnalysis
			                    		-On:UserPointOfSaleId-UserPointOfSaleId
			                    }}
			                    {{
			                    	-InnerJoin
			                    		-Dimension:Users
			                    			-Table:UsersCte
			                    		-Table:UsersPointOfSaleCte
			                    		-On:UserId-UserId
			                    }}
			                    {{
			                    	-InnerJoin
			                    		-Dimension:PointsOfSale
			                    			-Table:PointsOfSaleCte
			                    		-Table:UsersPointOfSaleCte
			                    		-On:PointOfSaleId
			                    }}
			                    {{
			                    	-InnerJoin
			                    		-Dimension:Calendar
			                    			-Table:CalendarCte
			                    		-Table:VendorAnalysis
			                    		-On:Date-Date
			                    }}
			                    WHERE VendorAnalysis.Date BETWEEN @StartDate AND @EndDate
			                    {{
									-GroupBy 
										-Dimension:Users 
											-Table:UsersCte
										-Dimension:UsersPointOfSale 
											-Table:UsersPointOfSaleCte
										-Dimension:PointsOfSale 
											-Table:PointsOfSaleCte
										-Dimension:Calendar 
											-Table:CalendarCte 
											-WithPrimaryKey
		                    	}}


									SELECT {{
												-Fields 
													-Dimension:PointsOfSale 
														-Table:TargetTemporal
													-Dimension:Calendar 
														-Table:CalendarCte 
														-WithPrimaryKey
													-WithComma
				                    		}}
		                           		   SUM(SalesTarget) AS SalesTarget, SUM(AssignedHours) AS AssignedHours
				                        FROM (SELECT {{
														-Fields 
															-Dimension:PointsOfSale 
																-Table:PointsOfSaleCte
															-WithComma
				                    				 }}
							                         PointOfSaleAnalysis.Date, PointOfSaleAnalysis.SalesTarget, 0 AS AssignedHours
						                        FROM Fact.PointOfSaleAnalysis
						                        {{
						                        	-InnerJoin 
						                        		-Dimension:PointsOfSale 
						                        			-Table:PointsOfSaleCte 
						                        		-Table:PointOfSaleAnalysis 
						                        		-On:PointOfSaleId-PointOfSaleId
						                        	}}
						                        WHERE PointOfSaleAnalysis.Date BETWEEN @StartDate AND @EndDate
					                        UNION ALL
					                        SELECT {{
					                        			-Fields
					                        				-Dimension:PointsOfSale 
					                        					-Table:PointsOfSaleCte
					                        				-WithComma
				                    				 }}
						                           VendorAnalysis.Date, 0 AS SalesTarget, VendorAnalysis.AssignedHours
						                        FROM Fact.VendorAnalysis INNER JOIN Dim.UsersPointOfSale
							                        ON VendorAnalysis.UserPointOfSaleId = UsersPointOfSale.Id
								                        AND VendorAnalysis.Date BETWEEN @StartDate AND @EndDate
												{{
													-InnerJoin
														-Dimension:PointsOfSale 
															-Table:PointsOfSaleCte 
														-Table:UsersPointOfSale 
														-On:PointOfSaleId-PointOfSaleId
												}}
					                        ) AS TargetTemporal
					                    {{
					                    	-InnerJoin
					                    		-Dimension:Calendar 
					                    			-Table:CalendarCte 
					                    		-Table:TargetTemporal 
					                    		-On:Date-Date
					                    }}
										{{
											-GroupBy
												-Dimension:PointsOfSale
													-Table:TargetTemporal
												-Dimension:Calendar
													-Table:CalendarCte
													-WithPrimaryKey
                    					}}

Else.Cte:

									SELECT {{
												-Fields
													-Dimension:Calendar
														-Table:CalendarCte
														-WithPrimaryKey
													-WithComma
				                    		}}
		                           		   SUM(SalesTarget) AS SalesTarget, SUM(AssignedHours) AS AssignedHours
				                        FROM (SELECT PointOfSaleAnalysis.Date, PointOfSaleAnalysis.SalesTarget, 0 AS AssignedHours
						                        FROM Fact.PointOfSaleAnalysis
						                        WHERE PointOfSaleAnalysis.Date BETWEEN @StartDate AND @EndDate
					                        UNION ALL
					                        SELECT VendorAnalysis.Date, 0 AS SalesTarget, VendorAnalysis.AssignedHours
						                        FROM Fact.VendorAnalysis
						                        WHERE VendorAnalysis.Date BETWEEN @StartDate AND @EndDate
					                        ) AS TargetTemporal
					                    {{
					                    	-InnerJoin
					                    		-Dimension:Calendar
					                    			-Table:CalendarCte
					                    		-RelatedTo:TargetTemporal
					                    		-On:Date-Date
					                    }}
										{{
											-GroupBy 
												-Dimension:Calendar
													-Table:CalendarCte
													-WithPrimaryKey
                    					}}

With.Cte:

					SELECT {{
								-Fields
									-Dimension:Users 
										-Table:SalesAnalysisBaseCte 
										-AdditionalTable:TargetBaseCte
										-CheckIfNull
									-Dimension:UsersPointOfSale 
										-Table:SalesAnalysisBaseCte 
										-AdditionalTable:TargetBaseCte
										-CheckIfNull
									-Dimension:PointsOfSale
										-Table:SalesAnalysisBaseCte
										-AdditionalTable:TargetBaseCte
										-CheckIfNull
									-Dimension:Calendar 
										-Table:SalesAnalysisBaseCte 
										-AdditionalTable:TargetBaseCte 
										-CheckIfNull
										-WithPrimaryKey
									-WithComma
                    		}}
							{{
								-Fields 
									-Dimension:Products
										-Table:SalesAnalysisBaseCte
									-WithComma
							}}
							SalesAnalysisBaseCte.Sales, SalesAnalysisBaseCte.SalesTaxesIncluded, SalesAnalysisBaseCte.SalesTaxesExcluded,
							SalesAnalysisBaseCte.SalesQuantityNoRefund, SalesAnalysisBaseCte.SalesAmountTaxesIncludedNoRefund,
							SalesAnalysisBaseCte.Transactions,
							TargetBaseCte.SalesTarget, TargetBaseCte.AssignedHours
						FROM SalesAnalysisBaseCte
	                    {{
	                    	-FullJoin 
	                    		-Dimension:UsersPointOfSale
	                    			-Table:TargetBaseCte
	                    		-Table:SalesAnalysisBaseCte
	                    		-On:RequestFields
	                    }}
	                    {{
	                    	-FullJoin
	                    		-Dimension:Users
	                    			-Table:TargetBaseCte
	                    		-Table:SalesAnalysisBaseCte
	                    		-OnRequestFields
	                    }}
	                    {{
	                    	-FullJoin
	                    		-Dimension:PointsOfSale
	                    			-Table:TargetBaseCte
	                    		-Table:SalesAnalysisBaseCte
	                    		-OnRequestFields
	                    }}
	                    {{
	                    	-FullJoin
								-Dimension:Calendar 
									-Table:TargetBaseCte 
	                    		-Table:SalesAnalysisBaseCte
	                    		-OnRequestFields
	                    }}

Then.Cte:

							SELECT {{
										-Fields
											-Dimension:PointsOfSale
												-Table:PointsOfSaleCte
											-Dimension:Calendar
												-Table:CalendarCte
												-WithPrimaryKey
											-WithComma
				                    }}
				                    SUM(CustomerFlowAnalysis.InternalCustomerFlow) AS InternalCustomerFlow,
				                    SUM(CustomerFlowAnalysis.ExternalCustomerFlow) AS ExternalCustomerFlow
			                    FROM Fact.CustomerFlowAnalysis
								{{
									-InnerJoin 
										-Dimension:PointsOfSale
											-Table:PointsOfSaleCte
										-Table:CustomerFlowAnalysis
										-On:PointOfSaleId-PointOfSaleId
								}}
								{{
									-InnerJoin
										-Dimension:Calendar 
											-Table:CalendarCte 
										-Table:CustomerFlowAnalysis 
										-On:Date-Date
								}}
								{{
									-GroupBy
										-Dimension:PointsOfSale
											-Table:PointsOfSaleCte
										-Dimension:Calendar
											-Table:CalendarCte
											-WithPrimaryKey
                    			}}
